"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import { useSearchParams } from "next/navigation";
import { Loader2, SendHorizontal, Sparkles, Star } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";
type ChatMessage = {
  id: string;
  sender: "customer" | "agent" | "ai" | "system";
  body: string;
  created_at: string;
};
export function WidgetChat() {
  const searchParams = useSearchParams();
  const token = searchParams.get("token") ?? "";
  const storageKey = `supportos-chat-${token.slice(0, 8)}`;
  const [ticketId, setTicketId] = useState<string | null>(null);
  const [hydrated, setHydrated] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [status, setStatus] = useState<string>("open");
  const [rating, setRating] = useState<number | null>(null);
  const [email, setEmail] = useState("");
  const [name, setName] = useState("");
  const [input, setInput] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [sending, setSending] = useState(false);
  const bottomRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    // Deferred so hydration completes before state updates.
    const t = setTimeout(() => {
      setTicketId(localStorage.getItem(storageKey));
      setHydrated(true);
    }, 0);
    return () => clearTimeout(t);
  }, [storageKey]);
  const poll = useCallback(async () => {
    if (!ticketId) return;
    try {
      const res = await fetch(`/api/channels/chat?token=${encodeURIComponent(token)}&ticketId=${encodeURIComponent(ticketId)}`);
      if (res.status === 404) {
        localStorage.removeItem(storageKey);
        setTicketId(null);
        return;
      }
      const data = await res.json();
      if (data.messages) setMessages(data.messages);
      if (data.status) setStatus(data.status);
      setRating(data.rating ?? null);
    } catch {
      // Network hiccup — keep the last known messages.
    }
  }, [ticketId, token, storageKey]);
  useEffect(() => {
    if (!ticketId) return;
    const first = setTimeout(poll, 0);
    const interval = setInterval(poll, 4000);
    return () => {
      clearTimeout(first);
      clearInterval(interval);
    };
  }, [ticketId, poll]);
  useEffect(() => {
    bottomRef.current?.scrollIntoView({
      behavior: "smooth"
    });
  }, [messages.length]);
  async function send() {
    const message = input.trim();
    if (!message || sending) return;
    setSending(true);
    setError(null);
    try {
      if (!ticketId) {
        const res_0 = await fetch("/api/channels/chat", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            token,
            action: "start",
            email,
            name,
            message
          })
        });
        const data_0 = await res_0.json();
        if (!res_0.ok) throw new Error(data_0.error ?? "Something went wrong");
        localStorage.setItem(storageKey, data_0.ticketId);
        setTicketId(data_0.ticketId);
        setMessages([{
          id: "local",
          sender: "customer",
          body: message,
          created_at: new Date().toISOString()
        }]);
      } else {
        const res_1 = await fetch("/api/channels/chat", {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            token,
            action: "reply",
            ticketId,
            message
          })
        });
        const data_1 = await res_1.json();
        if (!res_1.ok) throw new Error(data_1.error ?? "Something went wrong");
        setMessages(m => [...m, {
          id: `local-${Date.now()}`,
          sender: "customer",
          body: message,
          created_at: new Date().toISOString()
        }]);
        setTimeout(poll, 1500);
      }
      setInput("");
    } catch (e) {
      setError(e instanceof Error ? e.message : "Something went wrong");
    } finally {
      setSending(false);
    }
  }
  if (!hydrated) return null;
  return <div className="flex h-dvh flex-col bg-background">
      <header className="flex shrink-0 items-center gap-2 border-b px-4 py-3">
        <div className="flex size-7 items-center justify-center rounded-lg bg-primary text-primary-foreground">
          <Sparkles className="size-3.5" />
        </div>
        <div>
          <p className="text-sm font-semibold leading-tight">Support</p>
          <p className="text-[11px] text-muted-foreground">
            We usually reply within minutes
          </p>
        </div>
      </header>

      {!ticketId ? <form className="flex flex-1 flex-col justify-center gap-3 p-5" onSubmit={e_0 => {
      e_0.preventDefault();
      send();
    }}>
          <p className="mb-1 text-sm text-muted-foreground">
            Hi! Tell us who you are and how we can help.
          </p>
          <Input placeholder="Your name (optional)" value={name} onChange={e_1 => setName(e_1.target.value)} />
          <Input type="email" required placeholder="you@email.com" value={email} onChange={e_2 => setEmail(e_2.target.value)} />
          <Textarea required placeholder="How can we help?" value={input} onChange={e_3 => setInput(e_3.target.value)} className="min-h-24" />
          {error && <p className="text-xs text-destructive">{error}</p>}
          <Button type="submit" disabled={sending}>
            {sending && <Loader2 className="size-4 animate-spin" />}
            Start chat
          </Button>
        </form> : <>
          <div className="flex-1 space-y-3 overflow-y-auto p-4">
            {(status === "resolved" || status === "closed") && rating === null && <div className="rounded-xl border bg-card p-3 text-center">
                  <p className="mb-2 text-xs text-muted-foreground">
                    This conversation was resolved. How did we do?
                  </p>
                  <div className="flex justify-center gap-1.5">
                    {[1, 2, 3, 4, 5].map(n => <button key={n} type="button" aria-label={`Rate ${n} out of 5`} onClick={async () => {
              setRating(n);
              await fetch("/api/channels/chat", {
                method: "POST",
                headers: {
                  "Content-Type": "application/json"
                },
                body: JSON.stringify({
                  token,
                  action: "rate",
                  ticketId,
                  rating: n
                })
              }).catch(() => setRating(null));
            }} className="rounded-lg p-1 text-muted-foreground transition-colors hover:text-amber-400">
                        <Star className="size-5" />
                      </button>)}
                  </div>
                </div>}
            {rating !== null && <div className="rounded-xl border bg-card p-3 text-center">
                <div className="flex justify-center gap-0.5">
                  {[1, 2, 3, 4, 5].map(n_0 => <Star key={n_0} className={cn("size-4", n_0 <= rating ? "fill-amber-400 text-amber-400" : "text-muted-foreground/40")} />)}
                </div>
                <p className="mt-1.5 text-xs text-muted-foreground">
                  Thanks for your feedback!
                </p>
              </div>}
            {messages.map(message_0 => {
          const mine = message_0.sender === "customer";
          return <div key={message_0.id} className={cn("flex", mine ? "justify-end" : "justify-start")}>
                  <div className={cn("max-w-[80%] whitespace-pre-wrap rounded-2xl px-3.5 py-2 text-sm leading-relaxed", mine ? "rounded-br-sm bg-primary text-primary-foreground" : "rounded-bl-sm bg-muted")}>
                    {message_0.body}
                  </div>
                </div>;
        })}
            <div ref={bottomRef} />
          </div>

          <form className="shrink-0 border-t p-3" onSubmit={e_4 => {
        e_4.preventDefault();
        send();
      }}>
            {error && <p className="mb-2 text-xs text-destructive">{error}</p>}
            <div className="flex items-end gap-2">
              <Textarea value={input} onChange={e_5 => setInput(e_5.target.value)} placeholder="Write a message…" className="min-h-10 resize-none" onKeyDown={e_6 => {
            if (e_6.key === "Enter" && !e_6.shiftKey) {
              e_6.preventDefault();
              send();
            }
          }} />
              <Button type="submit" size="icon" disabled={sending || !input.trim()} aria-label="Send">
                {sending ? <Loader2 className="size-4 animate-spin" /> : <SendHorizontal className="size-4" />}
              </Button>
            </div>
          </form>
        </>}
    </div>;
}